detailed_optimizations.code_changes:
示例（保持 i-k-j 但对 j 寄存器分块，便于编译器向量化；假设行主序）：

```c
for (int i=0;i<_PB_NI;i++) {
  // 先做 beta 缩放（也可融合到下面见后续优化）
  for (int j=0;j<_PB_NJ;j++) C[i][j]*=beta;

  for (int k=0;k<_PB_NK;k++) {
    DATA_TYPE aik = alpha * A[i][k];
    int j=0;
    for (; j+7<_PB_NJ; j+=8) {
      // 让编译器生成 SIMD：
      #pragma omp simd
      for (int jj=0;jj<8;jj++)
        C[i][j+jj] += aik * B[k][j+jj];
    }
    for (; j<_PB_NJ; j++) C[i][j] += aik * B[k][j];
  }
}
```

进一步：把 C[i][j..j+7] 先 load 到局部数组/向量寄存器，k 循环内只更新寄存器，k 结束后一次性写回（需要把 k 放到最内层之外的结构，即 j-block 外层、k 内层）。

典型三层分块（块大小需按 L1/L2 调参；示例 BI,BJ,BK）：

```c
const int BI=64, BJ=128, BK=64;
for (int ii=0; ii<_PB_NI; ii+=BI)
  for (int jj=0; jj<_PB_NJ; jj+=BJ) {
    // 可在这里对 C 子块做 beta 缩放（见融合优化）
    for (int kk=0; kk<_PB_NK; kk+=BK)
      for (int i=ii; i<min(ii+BI,_PB_NI); i++)
        for (int k=kk; k<min(kk+BK,_PB_NK); k++) {
          DATA_TYPE aik = alpha * A[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+BJ,_PB_NJ); j++)
            C[i][j] += aik * B[k][j];
        }
  }
```

要点：让 B 的 (k,j) 子块在缓存中被多个 i 复用；让 C 的 (i,j) 子块在 kk 分块内反复更新但尽量驻留缓存。

最简单：并行 i（每线程独占一行 C）：

```c
#pragma omp parallel for schedule(static)
for (int i=0;i<_PB_NI;i++) {
  for (int j=0;j<_PB_NJ;j++) C[i][j]*=beta;
  for (int k=0;k<_PB_NK;k++) {
    DATA_TYPE aik = alpha * A[i][k];
    #pragma omp simd
    for (int j=0;j<_PB_NJ;j++) C[i][j] += aik * B[k][j];
  }
}
```

更好：与分块结合，对 (ii,jj) 2D tiles 并行，提升负载均衡并减少共享缓存争用。

在分块版本中：当 kk==0 时对 C 子块做一次缩放，否则不缩放：

```c
for (int ii=0; ii<NI; ii+=BI)
  for (int jj=0; jj<NJ; jj+=BJ)
    for (int kk=0; kk<NK; kk+=BK) {
      for (int i=ii; i<min(ii+BI,NI); i++)
        for (int j=jj; j<min(jj+BJ,NJ); j++)
          if (kk==0) C[i][j] *= beta; // 只做一次
      // 然后做该 tile 的乘加
      ...
    }
```

若不分块，也可在 k==0 时做：但会把缩放放到最内层附近，可能影响向量化/分支预测，不如 tile 级处理。

建议：默认关闭 DUMP，或将 prevent_dce 改为 checksum：

```c
DATA_TYPE s=0;
for(i=0;i<ni;i++) for(j=0;j<nj;j++) s += C[i][j];
fprintf(stderr, "%0.6lf\n", (double)s);
```

若必须输出：使用 setvbuf(POLYBENCH_DUMP_TARGET, NULL, _IOFBF, 1<<20) 增大缓冲；减少 fprintf 次数（拼接到大 buffer 再 fwrite）。

将 i-j-k 改为 i-k-j，并对 j 维做块化；在 k 循环外提 alpha*A[i][k]，对一段连续 j 做 FMA 累加。

示例（保持语义，便于编译器向量化）：
```c
for (int i=0;i<_PB_NI;i++)
  for (int j=0;j<_PB_NJ;j++) tmp[i][j]=0;

const int BJ = 64; // 依据 LLC/向量宽度调参
for (int i=0;i<_PB_NI;i++) {
  for (int kk=0; kk<_PB_NK; kk++) {
    DATA_TYPE aik = alpha * A[i][kk];
    for (int jj=0; jj<_PB_NJ; jj+=BJ) {
      int jend = (jj+BJ<_PB_NJ)?(jj+BJ):_PB_NJ;
      #pragma omp simd
      for (int j=jj; j<jend; j++) {
        tmp[i][j] += aik * B[kk][j];
      }
    }
  }
}
```
可进一步把 tmp 初始化融合到块内（首次 kk 时置零），减少一次写回。

把 `D[i][j]*=beta` 融合到计算块内；采用 i-k-j（这里 k 对应原 NJ 维）并对 j(=NL) 分块，使 C[k][j] 连续访问。

示例：
```c
const int BJ = 64;
for (int i=0;i<_PB_NI;i++) {
  for (int jj=0; jj<_PB_NL; jj+=BJ) {
    int jend = (jj+BJ<_PB_NL)?(jj+BJ):_PB_NL;
    // 先做 beta 缩放（仅对该块）
    #pragma omp simd
    for (int j=jj; j<jend; j++) D[i][j] *= beta;

    for (int kk=0; kk<_PB_NJ; kk++) {
      DATA_TYPE tik = tmp[i][kk];
      #pragma omp simd
      for (int j=jj; j<jend; j++) {
        D[i][j] += tik * C[kk][j];
      }
    }
  }
}
```
这样 C[kk][j] 在 j 内层为连续，D 写入为连续，且 beta 缩放不再需要全矩阵单独一遍。

基准测试时禁用 `polybench_prevent_dce(print_array(...))` 或改为计算校验和：
```c
DATA_TYPE checksum=0;
for(i) for(j) checksum += D[i][j];
fprintf(stderr, "%f\n", (double)checksum);
```
或使用 PolyBench 的宏开关关闭 DUMP。

用 cblas_dgemm/cblas_sgemm 替换三重循环。示例（以 double 为例）：

#include <cblas.h>
...
// E = A*B
cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans,
            ni, nj, nk,
            1.0, &A[0][0], nk,
                 &B[0][0], nj,
            0.0, &E[0][0], nj);

// F = C*D
cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans,
            nj, nl, nm,
            1.0, &C[0][0], nm,
                 &D[0][0], nl,
            0.0, &F[0][0], nl);

// G = E*F
cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans,
            ni, nl, nj,
            1.0, &E[0][0], nj,
                 &F[0][0], nl,
            0.0, &G[0][0], nl);

注意：DATA_TYPE 若为 float 则用 cblas_sgemm；并确保链接 OpenBLAS/MKL/BLIS。

若不能用 BLAS，建议对每个 GEMM 做分块并对右矩阵按块转置/打包。

(1) 最小侵入：对 D 做一次转置 Dt[NL][NM]，把 D[k][j] 变为 Dt[j][k]，使 k 循环访问连续：

// 预处理：Dt[j][k] = D[k][j]
for (int j=0;j<nl;j++)
  for (int k=0;k<nm;k++)
    Dt[j][k] = D[k][j];

// F[i][j] = sum_k C[i][k] * Dt[j][k]
for (int i=0;i<nj;i++)
  for (int j=0;j<nl;j++) {
    DATA_TYPE sum = 0;
    for (int k=0;k<nm;k++) sum += C[i][k]*Dt[j][k];
    F[i][j]=sum;
  }

(2) 更进一步：i/j/k 三维分块（例如 Ti=32,Tj=32,Tk=64），并在 k-block 内对右矩阵块做 packing 到连续缓冲区（Bpack/Dpack/Fpack），配合 #pragma omp parallel for collapse(2) 与 #pragma omp simd。

同时把 E/F/G 的初始化与累加融合为寄存器累加（sum）避免每次读写 E[i][j]。

并行化外层 i/j，并在内层 k 做向量化；同时采用 j-block 让 F[k][j] 的访问更连续。

示例（不改变数学结果）：

#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<ni; ii+=Ti)
  for (int jj=0; jj<nl; jj+=Tj)
    for (int i=ii; i<min(ii+Ti,ni); i++)
      for (int j=jj; j<min(jj+Tj,nl); j++) {
        DATA_TYPE sum = 0;
        #pragma omp simd reduction(+:sum)
        for (int k=0; k<nj; k++)
          sum += E[i][k] * F[k][j];
        G[i][j] = sum;
      }

并配合编译选项：-O3 -march=native -ffast-math(可选) -fopenmp；以及为数组添加 restrict（若可改宏/声明）以帮助向量化。

将 i-k-j 改为 i-j-k（或 i-j 分块后内层 k），并对 (i,j) 做 tile；对每个 tile 的 C 子块用寄存器/局部数组累加，k 维度做小块以适配 L1/L2。

示例（保持下三角 j<=i，简化版 blocking）：
```c
#define BI 64
#define BJ 64
#define BK 64
for (int ii=0; ii<_PB_N; ii+=BI) {
  int iimax = (ii+BI<_PB_N)? ii+BI : _PB_N;
  for (int jj=0; jj<=ii; jj+=BJ) {
    int jjmax = (jj+BJ<iimax)? jj+BJ : iimax; // 保证 j<=i
    // 先缩放 C tile
    for (int i=ii; i<iimax; ++i)
      for (int j=jj; j<jjmax && j<=i; ++j)
        C[i][j] *= beta;

    // 累加 alpha*A*A^T
    for (int kk=0; kk<_PB_M; kk+=BK) {
      int kkmax = (kk+BK<_PB_M)? kk+BK : _PB_M;
      for (int i=ii; i<iimax; ++i) {
        for (int j=jj; j<jjmax && j<=i; ++j) {
          DATA_TYPE sum = C[i][j];
          #pragma omp simd reduction(+:sum)
          for (int k=kk; k<kkmax; ++k)
            sum += alpha * A[i][k] * A[j][k];
          C[i][j] = sum;
        }
      }
    }
  }
}
```
进一步：把 (i,j) 内层改为小寄存器块（如 i 方向 4、j 方向 4），一次加载 A[i][k] 向量并复用到多个 j；或直接调用 BLAS（见后续）。

按 i（或 ii tile）并行，每个线程写独立的 C 行/块，天然无写冲突；对大问题在 NUMA 上 first-touch 初始化 C/A。

```c
#pragma omp parallel for schedule(static)
for (int i=0; i<_PB_N; i++) {
  for (int j=0; j<=i; j++) C[i][j] *= beta;
  for (int k=0; k<_PB_M; k++) {
    DATA_TYPE aik = A[i][k];
    #pragma omp simd
    for (int j=0; j<=i; j++)
      C[i][j] += alpha * aik * A[j][k];
  }
}
```
配合分块版本：对 ii 外层 `#pragma omp parallel for`，并设置 `OMP_PROC_BIND=close`、`OMP_PLACES=cores`；NUMA：初始化时并行写各自负责的行块。

方案A（打包/转置）：预先构造 AT[k][i]=A[i][k]，使得访问 A[j][k] 变为 AT[k][j] 连续。
```c
// 预处理一次：AT[M][N]
for (int i=0;i<n;i++)
  for (int k=0;k<m;k++)
    AT[k][i]=A[i][k];
// 更新时用 AT
C[i][j] += alpha * A[i][k] * AT[k][j];
```
方案B（推荐，最高收益/最低维护）：直接调用 BLAS。
- 若允许全矩阵：用 GEMM：C = alpha*A*A^T + beta*C，然后只保留下三角。
- 若用 CBLAS/LAPACK：调用 `cblas_dsyrk`/`cblas_ssyrk`（UPLO=Lower, Trans=NoTrans）。
示例（double）：
```c
cblas_dsyrk(CblasRowMajor, CblasLower, CblasNoTrans,
            n, m, alpha, &A[0][0], m, beta, &C[0][0], n);
```
注意：RowMajor 下 lda/ldc 取列数（m/n）。

把 `C[i][j]*=beta` 融入第一次 k 迭代或在寄存器累加前做一次：
```c
for (int i=0;i<_PB_N;i++) {
  for (int j=0;j<=i;j++) {
    DATA_TYPE sum = beta * C[i][j];
    for (int k=0;k<_PB_M;k++) sum += alpha*A[i][k]*A[j][k];
    C[i][j]=sum;
  }
}
```
并加 `#pragma omp simd` 到 j 或 k（视布局/阻塞而定）。

确保计时区间不包含 print；PolyBench 通常已将计时包住 kernel，但若运行配置导致 I/O 影响整体 wall time，可：
- 编译时关闭 DUMP（PolyBench 宏）；
- 用 checksum 替代全量打印：
```c
DATA_TYPE s=0;
for(i=0;i<n;i++) for(j=0;j<n;j++) s+=C[i][j];
printf("%f\n", (double)s);
```

方案A（一次性转置，最直接）：
1) 分配 AT[M][N], BT[M][N]
2) 预处理：for (i=0;i<n;i++) for(k=0;k<m;k++){ AT[k][i]=A[i][k]; BT[k][i]=B[i][k]; }
3) 内核改为使用AT/BT：
for (i=0;i<n;i++){
  for (j=0;j<=i;j++) C[i][j]*=beta;
  for (k=0;k<m;k++){
    const DATA_TYPE aik = AT[k][i];
    const DATA_TYPE bik = BT[k][i];
    const DATA_TYPE s1 = alpha*bik;
    const DATA_TYPE s2 = alpha*aik;
    for (j=0;j<=i;j++){
      C[i][j] += AT[k][j]*s1 + BT[k][j]*s2;
    }
  }
}
这样j内层访问AT[k][j]/BT[k][j]为连续。

方案B（按块pack，避免全转置额外内存）：对k分块Kc，对j分块Jc，把A[j..j+Jc][k..k+Kc]与B同块打包到连续buffer，再更新C块。

将(i,j)空间做二维分块（仅下三角）：
for (ii=0; ii<n; ii+=Ti)
  for (jj=0; jj<=ii; jj+=Tj){
    // 1) 先对C块做beta缩放（只处理下三角有效区域）
    for (i=ii;i<min(ii+Ti,n);i++)
      for (j=jj;j<min(jj+Tj,i+1);j++) C[i][j]*=beta;

    // 2) k分块
    for (kk=0; kk<m; kk+=Tk){
      // 可选：pack A/B 子块到连续buffer
      for (i=ii;i<...;i++){
        for (j=jj;j<...;j++){
          DATA_TYPE cij = C[i][j];
          for (k=kk;k<min(kk+Tk,m);k++)
            cij += alpha*(A[j][k]*B[i][k] + B[j][k]*A[i][k]);
          C[i][j]=cij;
        }
      }
    }
  }
关键点：把C[i][j]提升到寄存器(cij)并在Tk范围内累加，减少对C的load/store次数；配合pack/转置可进一步提升。

1) 外提alpha乘法，减少标量运算：
在k循环内：
const DATA_TYPE aik = A[i][k];
const DATA_TYPE bik = B[i][k];
const DATA_TYPE s1 = alpha*bik;
const DATA_TYPE s2 = alpha*aik;
然后内层：C[i][j] += A[j][k]*s1 + B[j][k]*s2;
2) 给指针加restrict（若PolyBench宏允许）：
void kernel_syr2k(..., DATA_TYPE (*restrict C)[N], ...)
3) 确保数据对齐（PolyBench通常已对齐，但可检查POLYBENCH_2D_ARRAY_DECL实现）；
4) 对j循环加#pragma omp simd（在转置/pack后更有效）：
#pragma omp simd
for (j=0;j<=i;j++) ...
5) 编译选项：-O3 -march=native -ffast-math（若允许）

并行i或(ii,jj)块最安全：
#pragma omp parallel for schedule(static)
for (i=0;i<n;i++){
  for (j=0;j<=i;j++) C[i][j]*=beta;
  for (k=0;k<m;k++){
    const DATA_TYPE s1 = alpha*B[i][k];
    const DATA_TYPE s2 = alpha*A[i][k];
    for (j=0;j<=i;j++) C[i][j] += A[j][k]*s1 + B[j][k]*s2;
  }
}
更推荐与分块结合：并行(ii,jj)块，提升cache局部性并减少线程间带宽争用。
注意：每个(i,j)只被一个线程写，天然无竞争。

将 sum[p]=0 初始化保留，但把内层从 (p 外, s 内) 改为 (s 外, p 内)，使 A[r][q][s] 只加载一次并用于更新所有 p；同时对 p 循环加 SIMD pragma。

示例：
for (r=0;r<_PB_NR;r++)
  for (q=0;q<_PB_NQ;q++) {
    for (p=0;p<_PB_NP;p++) sum[p]=0;
    for (s=0;s<_PB_NP;s++) {
      DATA_TYPE a = A[r][q][s];
      #pragma omp simd
      for (p=0;p<_PB_NP;p++)
        sum[p] += a * C4[s][p];
    }
    for (p=0;p<_PB_NP;p++) A[r][q][p]=sum[p];
  }

要点：C4[s][p] 在 p 内层变为连续访问（行主序），sum[p] 连续，利于 SIMD；A 标量 a 复用。

对 p 做块大小 BP（如 64/128，按数据类型与 SIMD 宽度调参），每次只维护一小段 sum[p0:p0+BP) 在 L1/寄存器中。

示例：
const int BP = 128;
for (p0=0;p0<_PB_NP;p0+=BP) {
  int pend = (p0+BP<_PB_NP)?p0+BP:_PB_NP;
  for (p=p0;p<pend;p++) sum[p]=0;
  for (s=0;s<_PB_NP;s++) {
    DATA_TYPE a = A[r][q][s];
    #pragma omp simd
    for (p=p0;p<pend;p++) sum[p] += a * C4[s][p];
  }
  for (p=p0;p<pend;p++) A[r][q][p]=sum[p];
}

若允许额外临时缓冲，可用局部数组 DATA_TYPE sum_blk[BP] 替代全局 sum，减少别名与提升寄存器分配。

并行 r/q 两层之一或 collapse(2)。注意 sum 需线程私有：使用线程私有缓冲（局部数组或在并行域内分配）。

示例：
#pragma omp parallel
{
  DATA_TYPE *sum_priv = (DATA_TYPE*)aligned_alloc(64, np*sizeof(DATA_TYPE));
  #pragma omp for collapse(2) schedule(static)
  for (int r=0;r<_PB_NR;r++)
    for (int q=0;q<_PB_NQ;q++) {
      ... 使用 sum_priv ...
    }
  free(sum_priv);
}

避免共享 sum 引发数据竞争与伪共享。

把 A 视为二维矩阵 A2D[(r*nq+q)][s]，计算 A2D = A2D * C4。

实现路径：
1) 重新解释/拷贝 A 为连续二维（通常 A 本身在最后一维连续，但 (r,q) 行也连续，可直接按 leading dimension=NP 处理）。
2) 调用 cblas_dgemm / sgemm：
C = A2D * C4，其中 C 写回 A2D（可用临时缓冲避免覆盖输入）。

伪代码：
// M = nr*nq, K = np, N = np
// A2D: MxK, B=C4: KxN, Out: MxN
cblas_dgemm(RowMajor, NoTrans, NoTrans, M, N, K, 1.0, A2D, K, C4, N, 0.0, Out, N);
memcpy(A2D, Out, M*N*sizeof(DATA_TYPE));

核心思路：对 j 做分块 JB，使 A 的一小块列驻留在 LLC/L2；对每个 j 块：先计算该块所有 R[k][j]（对 i 做向量化/并行归约），再用同一块数据更新 A。
示例（伪代码，保持数值顺序不变：先算完 R 再更新 A）：

const int JB=32; // 依据缓存调参
for (k=0;k<n;k++) {
  // nrm + normalize 同原逻辑
  ...
  for (int jb=k+1; jb<n; jb+=JB) {
    int jend = (jb+JB<n)? jb+JB : n;
    // 1) 计算 R[k][j] for j in [jb,jend)
    for (int j=jb;j<jend;j++) R[k][j]=0;
    // i 维归约：可 OpenMP + SIMD
    #pragma omp parallel for
    for (int j=jb;j<jend;j++) {
      DATA_TYPE sum=0;
      #pragma omp simd reduction(+:sum)
      for (int i=0;i<m;i++) sum += Q[i][k]*A[i][j];
      R[k][j]=sum;
    }
    // 2) 更新 A[:,j]
    #pragma omp parallel for collapse(2)
    for (int j=jb;j<jend;j++) {
      DATA_TYPE rkj = R[k][j];
      #pragma omp simd
      for (int i=0;i<m;i++) A[i][j] -= Q[i][k]*rkj;
    }
  }
}

